package pkg

import (
	"fmt"
	"strings"
)

// sumAbsoluteValuesWithSummary returns the sum of absolute values of elements
// in values (positive added, negative contributes its absolute value). If
// includeSummary is true, a comma-separated summary is built: positive as "n,",
// negative as "(n),". If label is non-empty it is prepended as "label: ".
// Returns an error when the resulting sum is zero.
func sumAbsoluteValuesWithSummary(values []int, label string, includeSummary bool) (int, string, error) {
	var sum int
	var b strings.Builder
	for _, v := range values {
		if v > 0 {
			sum += v
			if includeSummary {
				fmt.Fprintf(&b, "%d,", v)
			}
		} else if v < 0 {
			sum -= v
			if includeSummary {
				fmt.Fprintf(&b, "(%d),", v)
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	summary := b.String()
	if label != "" {
		summary = label + ": " + summary
	}
	return sum, summary, nil
}

// sumLabeledValues sums positive elements, adds |negative| for negative elements,
// and optionally builds a comma-separated detail string (label prefix when non-empty).
// Returns an error when the computed result is zero.
func sumLabeledValues(values []int, label string, includeDetail bool) (sum int, detail string, err error) {
	var sb strings.Builder
	for _, v := range values {
		if v > 0 {
			sum += v
			if includeDetail {
				sb.WriteString(fmt.Sprintf("%d,", v))
			}
		} else if v < 0 {
			sum += -v
			if includeDetail {
				sb.WriteString(fmt.Sprintf("(%d),", v))
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if includeDetail {
		detail = strings.TrimSuffix(sb.String(), ",")
		if label != "" {
			detail = label + ": " + detail
		}
	}
	return sum, detail, nil
}

