package pkg

import (
	"fmt"
	"strings"
)

// SumAbsoluteAndFormat sums non-zero elements: positives as-is, negatives as absolute value.
// If includeFormat is true, it builds a comma-separated list (negatives in parentheses).
// Returns an error when the sum is zero (e.g. all zeros or empty slice).
func SumAbsoluteAndFormat(numbers []int, label string, includeFormat bool) (sum int, formatted string, err error) {
	if numbers == nil {
		return 0, "", fmt.Errorf("nil slice for label %q", label)
	}
	var parts []string
	for _, n := range numbers {
		if n > 0 {
			sum += n
			if includeFormat {
				parts = append(parts, fmt.Sprintf("%d", n))
			}
		} else if n < 0 {
			sum += -n
			if includeFormat {
				parts = append(parts, fmt.Sprintf("(%d)", n))
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if includeFormat && len(parts) > 0 {
		formatted = strings.Join(parts, ",")
		if label != "" {
			formatted = label + ": " + formatted
		}
	}
	return sum, formatted, nil
}

// SumSignedValues computes the sum of positive elements plus the sum of absolute
// values of negative elements. If formatDetail is true, it also builds a
// human-readable detail string. label is used as an optional prefix for that string.
// Returns an error when the computed total is zero.
func SumSignedValues(values []int, label string, formatDetail bool) (total int, detail string, err error) {
	var sb strings.Builder
	for _, v := range values {
		if v > 0 {
			total += v
			if formatDetail {
				sb.WriteString(fmt.Sprintf("%d,", v))
			}
		} else if v < 0 {
			total += -v
			if formatDetail {
				sb.WriteString(fmt.Sprintf("(%d),", v))
			}
		}
	}
	if total == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if label != "" {
		detail = label + ": " + sb.String()
	} else {
		detail = sb.String()
	}
	return total, detail, nil
}

